var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"원정의 무사 귀환을 경하드립니다, 예하.","JPN":"遠征から無事に帰還なさったこと、心より喜ばしく思います、猊下。","ENG":"I am glad you made a safe return from your expedition, Your Eminence.","TWN":"恭喜主教從遠征平安歸來。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그래, 모두가 애써 준 덕분이다.","JPN":"ああ、皆が力を尽くしてくれたおかげだ。","ENG":"Yes. It is because everyone did their part.","TWN":"是的，多虧有大家的幫忙。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"신도들의 기도와 악단의 연주가 태양문을 밝혔기에 이번 원정이 성사될 수 있었던 것이지.","JPN":"信徒たちの祈りと楽団の演奏が太陽の扉を照らしたからこそ、この度の遠征が無事終わったのであろう。","ENG":"This expedition was made possible because our followers' prayers and the orchestra's performance illuminated the Solar Gates.","TWN":"是信徒們的祈禱和樂隊的演奏照亮了太陽門，才能順利完成這次遠征。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그런데…","JPN":"ところで……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께선 돌아오시자마자, 데려온 아이의 이름을 성흔 순례단의 명단에 올리려 하셨더군요.","JPN":"猊下はお戻りの際、連れてきた子どもを聖痕の巡礼団に入れようとしたようですが。","ENG":"I noticed that, as soon as you returned, you attempted to register the child you brought for the Stigmata pilgrimage.","TWN":"主教剛回來不久就想讓您帶來的孩子加入聖痕朝聖團。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이번 원정에서 큰 공을 세운 아이다.","JPN":"この度の遠征で大きな手柄をたてた子どもだ。","ENG":"She has greatly contributed to this expedition.","TWN":"她在這次遠征立了大功。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대들처럼 연주와 기도는 하지 않았으나, 목숨 걸고 나를 보좌하여 마왕에 맞섰지.","JPN":"そなたたちのように演奏や祈りを捧げたわけではないが、命を懸けて我とともに魔王に立ち向かった。","ENG":"Though she did not pray or perform like the others, she was my aid who fought against the Demon Lord with her life.","TWN":"她雖然沒有像你們演奏和祈禱，卻冒著生命危險輔佐我共同對抗魔王。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아이의 갸륵함을 인정하고자 하는 예하의 심정은 이해하나, 멋대로 태양문 바깥을 떠돌던 이교도에게 특혜를 주신다면 교단의 반발이 있을 것입니다.","JPN":"子どもの勇姿を称えたい猊下のお気持ちはわかります。しかし、太陽の扉の外で彷徨っていた異教徒に特別な恩恵を与えては、教団が反発すると思われます。","ENG":"I understand you wish to acknowledge the child's deeds. Yet, giving special treatment to a pagan who used to wander on the other side of the Solar Gates will trigger a revolt from the Order.","TWN":"我能理解您對孩子的讚賞和認可，但如果您對一個太陽門外的異教徒提供這樣的特殊待遇，恐怕會受到教團的反對。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그런가…","JPN":"そうか……","ENG":"Is that so...","TWN":"是嗎……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"물론 이교도라고는 하지만, 그 아이 역시 엘리시온의 일원.","JPN":"もちろん異教徒でもエリシオンの一員。","ENG":"Although she is a pagan... that child is also a part of Elysion.","TWN":"雖然是異教徒，但她也是艾利森的一員。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"마왕 토벌에 기여한 자를 예우하진 못할 망정 처벌을 내리는 건 과한 처사겠죠.","JPN":"魔王討伐の貢献を称えるどころか罰を与えるのは酷い仕打ちでしょう。","ENG":"It would be excessive to punish someone who has contributed to defeating the Demon Lord.","TWN":"懲罰一個為討伐魔王做出貢獻的人是不公平的。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"역병에 감염되었을지도 모르니 저희가 건강만 살핀 뒤에 돌려보내겠습니다.","JPN":"疫病に感染している可能性もありますので、私たちが健康状態を確認してから送り返します。","ENG":"I shall check her health first and see if she is infected by the plague before sending her back.","TWN":"我們要檢查一下她的健康狀況，如果確定沒有被瘟疫傳染就會把她送回去。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"알겠다. 그대의 의견을 존중하도록 하지.","JPN":"わかった。そなたの意見を尊重しよう。","ENG":"Very well. I respect your decision.","TWN":"好吧，我尊重你的意見。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"추기경께서 직접 팔라딘을 위임하려 하시다니 별난 일이네요.","JPN":"枢機卿が直接パラディンへ委任するとは珍しいわね。","ENG":"Strange that the Cardinal is appointing a paladin herself.","TWN":"樞機主教竟然要親自委任聖騎士，真稀奇。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"늘 베풀기만 하시던 분께서 누군가를 갖고 싶어하는 모습을 보이실 줄이야.","JPN":"いつも自らが施すのみの方が誰かを必要とする姿を見せるとは。","ENG":"She was always so giving. I didn't expect to see her want someone like this.","TWN":"沒想到一向樂善好施的人也會想把一個人占為己有。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NAME_HIDE","text":{"KOREA":"이번 원정에서 어떤 심경의 변화라도 겪으신 걸까요?","JPN":"今回の遠征で何か心情の変化でもあったのかな？","ENG":"Do you think she had a change of heart during the expedition?","TWN":"難道在這次遠征中經歷了什麼心理變化嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"글쎄요, 카르멘.","JPN":"どうなんでしょうか、カルメン。","ENG":"Perhaps, Carmen.","TWN":"我也不清楚，卡門。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"제가 듣기엔, 예하의 목소리는 평소 그대로이셨습니다.","JPN":"私には猊下の声はいつもと変わらないように思えました。","ENG":"Her Eminence's voice was no different than before.","TWN":"主教的聲音和往常沒有兩樣。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};